#include<bits/stdc++.h>
using namespace std;
int n,k,cnt=0;
bool v[10001];
bool hua(int x){
    for(int i=x;i<=n;i+=x){
        if(i>n) break;

        if(!v[i]) cnt++;
        v[i]=1;
        if(cnt==k){
            cout<<i;
            return 0;
        }
    }
    return 1;
}
int main(){
    cin>>n>>k;
    for(int i=2;i<=n;i++){
        if(!v[i]){
            if(!hua(i)){
                return 0;
            }
        }
    }
}
